124		s.mu.Lock()
125		out := Stats{Enabled: s.enabled, Items: make(map[string]*ServiceStats, len(s.items))}
126		for key, item := range s.items {
127			copyItem := *item
128			out.Items[key] = &copyItem
129		}
130		s.mu.Unlock()
131		if s.enabled {
