138	// countingRoundTripper wraps an HTTP transport to record transfer stats
139	// and feed per-side byte counters consumed by the live progress ticker.
140	type countingRoundTripper struct {
141		base  http.RoundTripper
142		label string
143		stats *statsCollector
144	}
145	
146	func (rt *countingRoundTripper) RoundTrip(req *http.Request) (*http.Response, error) {
147		side := rt.stats.side(rt.label)
148	
149		// Wrap the request body so upload bytes (receive-pack POSTs) feed
150		// the per-side counter as they stream out, not just on round-trip
151		// completion. Skipped when there is no body (most GETs).
152		if req.Body != nil {
153			req.Body = &countingReadCloser{ReadCloser: req.Body, side: side}
154		}
155	
156		res, err := rt.base.RoundTrip(req)
157		if err != nil {
158			return nil, fmt.Errorf("round trip: %w", err)
159		}
160	
161		serviceName := req.Header.Get(gitproto.StatsPhaseHeader)
162		if serviceName == "" {
163			serviceName = req.URL.Query().Get("service")
164			if serviceName == "" {
165				serviceName = strings.TrimPrefix(req.URL.Path[strings.LastIndex(req.URL.Path, "/")+1:], "/")
166			}
167		}
168		name := strings.TrimSpace(rt.label + " " + serviceName)
169		requestBytes := req.ContentLength
170		if requestBytes < 0 {
171			requestBytes = 0
172		}
173	
174		res.Body = &countingReadCloser{
175			ReadCloser: res.Body,
176			side:       side,
177			onClose: func(n int64) {
178				rt.stats.recordRoundTrip(name, requestBytes, n)
179			},
180		}
181		return res, nil
182	}
183	
184	type countingReadCloser struct {
185		io.ReadCloser
186	
187		n       int64
188		side    *sideCounter
189		onClose func(int64)
190	}
